    public void actionPerformed(ActionEvent e) {
        output.append("=== ActionEvent ===\n");
        output.append("Source : " + e.getSource().getClass().getName() + "\n");
        output.append("ID     : " + e.getID() + "\n");
        output.append("Command: " + e.getActionCommand() + "\n");
        output.append("Time   : " + e.getWhen() + "\n\n");
    }

    public void mouseClicked(MouseEvent e) {
        output.append("=== MouseEvent ===\n");
        output.append("Source     : " + e.getSource().getClass().getName() + "\n");
        output.append("ID         : " + e.getID() + "\n");
        output.append("Position   : (" + e.getX() + ", " + e.getY() + ")\n");
        output.append("Click count: " + e.getClickCount() + "\n\n");
    }

    public void keyPressed(KeyEvent e) {
        output.append("=== KeyEvent ===\n");
        output.append("Source   : " + e.getSource().getClass().getName() + "\n");
        output.append("ID       : " + e.getID() + "\n");
        output.append("KeyChar  : " + e.getKeyChar() + "\n");
        output.append("KeyCode  : " + e.getKeyCode() + "\n");
        output.append("KeyText  : " + e.getKeyText(e.getKeyCode()) + "\n\n");
    }

    public void keyReleased(KeyEvent e) {}
    public void keyTyped(KeyEvent e) {}
    public void mousePressed(MouseEvent e) {}
    public void mouseReleased(MouseEvent e) {}
    public void mouseEntered(MouseEvent e) {}
    public void mouseExited(MouseEvent e) {}

    public static void main(String[] args) {
        EventDemo d = new EventDemo();
        d.setSize(500, 400);
        d.setVisible(true);
    }
}
